// ============================================================================
// Well-known module IDs and ports
// ============================================================================

/// Well-known modules in the system (root, clock, etc.)
#[derive(Clone, Copy, Debug, PartialEq, Eq)]
pub enum WellKnownModule {
    /// The root output module
    RootOutput,
    /// The root clock module (provides playhead)
    RootClock,
    /// The signal exposed to the dsl
    RootInput,
    /// The instance of AudioIn thats connected to AudioIn but hidden from the user
    HiddenAudioIn,
}

impl WellKnownModule {
    /// Get the module ID string
    pub fn id(&self) -> &'static str {
        match self {
            WellKnownModule::RootOutput => "ROOT_OUTPUT",
            WellKnownModule::RootClock => "ROOT_CLOCK",
            WellKnownModule::RootInput => "ROOT_INPUT",
            // We also use this for the module type string
            WellKnownModule::HiddenAudioIn => "HIDDEN_AUDIO_IN",
        }
    }

    /// Get the default output port name for this module
    pub fn default_port(&self) -> &'static str {
        match self {
            WellKnownModule::RootOutput => "output",
            WellKnownModule::RootClock => "playhead",
            WellKnownModule::RootInput => "output",
            WellKnownModule::HiddenAudioIn => "input", // doesn't actually matter, only one port
        }
    }

    /// Create a Cable signal pointing to this module's default port at the given channel
    pub fn to_cable(&self, channel: usize, port: &str) -> Signal {
        Signal::Cable {
            module: self.id().into(),
            module_ptr: std::sync::Weak::new(),
            port: port.into(),
            channel,
            index_ptr: std::ptr::null(),
        }
    }

    /// Create a PolySignal with cables to this module's default port for the given channels
    pub fn to_poly_signal(&self, channels: &[usize], port: &str) -> crate::poly::PolySignal {
        crate::poly::PolySignal::poly(
            &channels
                .iter()
                .map(|&ch| self.to_cable(ch, port))
                .collect::<Vec<_>>(),
        )
    }
}

lazy_static! {
    pub static ref ROOT_ID: String = WellKnownModule::RootOutput.id().into();
    pub static ref ROOT_OUTPUT_PORT: &'static str = WellKnownModule::RootOutput.default_port();
    pub static ref ROOT_CLOCK_ID: String = WellKnownModule::RootClock.id().into();
    static ref RE_HZ: Regex = Regex::new(r"(?i)^(-?\d*\.?\d+)hz$").unwrap();
    static ref RE_MIDI: Regex = Regex::new(r"^(-?\d*\.?\d+)m$").unwrap();
    static ref RE_SCALE: Regex = Regex::new(r"^(-?\d*\.?\d+)s\(([^:]+):([^)]+)\)$").unwrap();
    static ref RE_NOTE: Regex = Regex::new(r"^([A-Ga-g])([#b]?)(-?\d+)?$").unwrap();
}

pub trait MessageHandler {
    fn handled_message_tags(&self) -> &'static [MessageTag] {
        &[]
    }

    fn handle_message(&self, _message: &Message) -> Result<()> {
        Ok(())
    }
}

pub trait StatefulModule {
    fn get_state(&self) -> Option<serde_json::Value> {
        None
    }
}

/// Trait for modules that need to perform work after the patch is updated.
/// Modules that need custom behavior should implement this trait and use the
/// `patch_update` flag in their `#[module(...)]` attribute.
pub trait PatchUpdateHandler {
    /// Called after the patch is updated and all modules are connected.
    /// Override to refresh caches or perform other post-update work.
    fn on_patch_update(&mut self);
}

// ============================================================================
// Block processing types

/// Determines how a module wrapper processes samples.
///
/// - `Block`: compute all `block_size` samples in one `ensure_processed()` call.
/// - `Sample`: compute exactly one sample per `ensure_processed()` call (used for
///   modules inside feedback cycles and ROOT_CLOCK/HiddenAudioIn which have
///   external per-sample data injection).
#[derive(Debug, Clone, Copy, PartialEq, Eq, Default)]
pub enum ProcessingMode {
    #[default]
    Block,
    Sample,
}

/// Per-sample external clock state injected into ROOT_CLOCK by the audio callback.
///
/// The callback pre-computes one entry per sample in the block by querying the
/// Link timeline. The ROOT_CLOCK wrapper injects the appropriate entry before
/// calling inner `Clock::update()` for each sample position.
#[derive(Debug, Clone, Copy, Default)]
pub struct ExternalClockState {
    /// Bar phase in [0, 1).
    pub bar_phase: f64,
    /// Tempo in BPM.
    pub bpm: f64,
    /// Whether the Link session is playing.
    pub playing: bool,
}

/// Implemented by signal-bearing types to receive the back-pointer to the
/// consuming wrapper's `index: Cell<usize>`.
///
/// The `Connect` derive macro generates an impl for every params struct,
/// iterating over each signal field. Base impls for primitive types are
/// no-ops so the generated code can call `inject_index_ptr` on any field.
pub trait InjectIndexPtr {
    /// Store `ptr` (which points to the consuming wrapper's `index` cell) so
    /// that `Signal::get_value()` can pass the correct sample index upstream.
    ///
    /// # Safety
    /// `ptr` must remain valid for the lifetime of this signal connection
    /// (i.e., until `connect()` is called again with a new patch).
    fn inject_index_ptr(&mut self, ptr: *const std::cell::Cell<usize>);
}

/// Blanket no-op impl for types that carry no signals.
macro_rules! noop_inject {
    ($($t:ty),*) => {
        $(impl InjectIndexPtr for $t {
            #[inline]
            fn inject_index_ptr(&mut self, _ptr: *const std::cell::Cell<usize>) {}
        })*
    };
}

noop_inject!(f32, f64, i32, i64, u32, u64, usize, bool, String, serde_json::Value);

impl<T: InjectIndexPtr> InjectIndexPtr for Option<T> {
    #[inline]
    fn inject_index_ptr(&mut self, ptr: *const std::cell::Cell<usize>) {
        if let Some(inner) = self {
            inner.inject_index_ptr(ptr);
        }
    }
}

impl<T: InjectIndexPtr> InjectIndexPtr for Vec<T> {
    #[inline]
    fn inject_index_ptr(&mut self, ptr: *const std::cell::Cell<usize>) {
        for item in self.iter_mut() {
            item.inject_index_ptr(ptr);
        }
    }
}

pub trait Sampleable: MessageHandler + Send + Sync {
    fn get_id(&self) -> &str;
    fn tick(&self) -> ();

    /// Process outputs up to the current block boundary.
    ///
    /// - `Block` mode: computes all `block_size` samples in one call.
    /// - `Sample` mode: computes exactly the next uncomputed sample.
    ///
    /// Idempotent: safe to call multiple times per block.
    /// Reentrancy-safe: if called while already computing (feedback cycle),
    /// returns immediately — callers read the previous block's last value.
    fn ensure_processed(&self) {}

    /// Read the computed value for `(port, ch)` at sample `index` within the
    /// current block. Calls `ensure_processed()` internally.
    ///
    /// Returns 0.0 for unknown ports or out-of-range indices.
    fn get_value_at(&self, _port: &str, _ch: usize, _index: usize) -> f32 {
        0.0
    }

    /// Pre-fill the audio input block for HiddenAudioIn modules.
    /// Only the HiddenAudioIn wrapper overrides this. Default: no-op.
    fn inject_audio_in_block(&self, _block: &[[f32; crate::poly::PORT_MAX_CHANNELS]]) {}
    fn get_module_type(&self) -> &str;
    fn connect(&self, patch: &Patch);
    /// Called after the patch is updated and all modules are connected.
    /// Modules can override this to refresh caches or perform other post-update work.
    fn on_patch_update(&self) {}
    /// Provide external clock synchronization data for the current block.
    /// `states` has one entry per sample in the block; an empty slice means
    /// no external sync is active this block.
    /// Only ROOT_CLOCK overrides this. Default: no-op.
    fn sync_external_clock(&self, _states: &[ExternalClockState]) {}
    fn get_state(&self) -> Option<serde_json::Value> {
        None
    }
    /// Get a buffer output by port name. Only modules that own buffers (like `$buffer`)
    /// override this. Default: no buffer outputs.
    ///
    /// # Safety contract
    ///
    /// Returns a reference into `UnsafeCell` internals. Safe only because callers
    /// respect phase separation: `connect()` phase (resolves pointers) and `process`
    /// phase (reads samples) never overlap. The returned `&Arc<BufferData>` must not
    /// be held across a `connect()` or `transfer_state_from()` call.
    fn get_buffer_output(&self, _port: &str) -> Option<&Arc<BufferData>> {
        None
    }
    /// Called on the main thread after construction and before the module
    /// is shipped to the audio thread. Lets the module allocate freely and
    /// do file I/O / heavy prep from the WAV data cache.
    ///
    /// Default: no-op. Modules that need wav preparation should use the
    /// `has_prepare_resources` flag in their `#[module(...)]` attribute to
    /// delegate to `prepare_resources_impl` on the inner module struct.
    fn prepare_resources(
        &self,
        _wav_data: &std::collections::HashMap<String, std::sync::Arc<WavData>>,
    ) {
    }
    /// Downcast to concrete type for state transfer.
    fn as_any(&self) -> &dyn std::any::Any;
    /// Transfer runtime state from an old module to this newly-constructed module.
    ///
    /// Called on the audio thread during the command-processing phase (between
    /// `tick()` cycles), before any `update()` calls. The implementation uses
    /// `UnsafeCell` to mutate through `&self` — this is safe because:
    ///
    /// 1. It runs only from the command-queue consumer, never during `process()`.
    /// 2. The proc macro guards against self-aliasing (`ptr::eq` check).
    /// 3. `old` is removed from `patch.sampleables` before this call, so no
    ///    concurrent `update()` can be in flight on it.
    fn transfer_state_from(&self, _old: &dyn Sampleable) {}
}

pub trait Module {
    fn install_constructor(map: &mut HashMap<String, SampleableConstructor>);
    fn get_schema() -> ModuleSchema;

    /// Register this module's params deserializer in the provided map.
    ///
    /// The key is the module type string (e.g. "sine"). The value is a function
    /// that deserializes a JSON params object (with `__argument_spans` already
    /// stripped) into a `CachedParams`.
    fn install_params_deserializer(map: &mut HashMap<String, crate::params::ParamsDeserializer>);
}

