// --- deserr impl (mirrors the serde shape: object with "type" discriminant) ---

impl<E: DeserializeError> deserr::Deserr<E> for Table {
    fn deserialize_from_value<V: IntoValue>(
        value: deserr::Value<V>,
        location: ValuePointerRef<'_>,
    ) -> StdResult<Self, E> {
        let mut map = match value {
            deserr::Value::Map(m) => m,
            _ => {
                return Err(deserr::take_cf_content(E::error::<V>(
                    None,
                    ErrorKind::Unexpected {
                        msg: "Table must be an object with a \"type\" field".to_string(),
                    },
                    location,
                )));
            }
        };

        let type_val = map.remove("type").and_then(|v| match v.into_value() {
            deserr::Value::String(s) => Some(s),
            _ => None,
        });

        let type_str = type_val.ok_or_else(|| {
            deserr::take_cf_content(E::error::<V>(
                None,
                ErrorKind::MissingField { field: "type" },
                location,
            ))
        })?;

        // Helper: pull a named PolySignal field out of the remaining map.
        fn take_signal<E2: DeserializeError, V2: IntoValue>(
            map: &mut impl DeserrMap<Value = V2>,
            field: &'static str,
            location: ValuePointerRef<'_>,
        ) -> StdResult<PolySignal, E2> {
            let raw = map.remove(field).ok_or_else(|| {
                deserr::take_cf_content(E2::error::<V2>(
                    None,
                    ErrorKind::MissingField { field },
                    location,
                ))
            })?;
            PolySignal::deserialize_from_value(raw.into_value(), location)
        }

        match type_str.as_str() {
            "identity" => Ok(Table::Identity),
            "mirror" => {
                let amount = take_signal::<E, V>(&mut map, "amount", location)?;
                Ok(Table::Mirror { amount })
            }
            "bend" => {
                let amount = take_signal::<E, V>(&mut map, "amount", location)?;
                Ok(Table::Bend { amount })
            }
            "sync" => {
                let ratio = take_signal::<E, V>(&mut map, "ratio", location)?;
                Ok(Table::Sync { ratio })
            }
            "fold" => {
                let amount = take_signal::<E, V>(&mut map, "amount", location)?;
                Ok(Table::Fold { amount })
            }
            "pwm" => {
                let width = take_signal::<E, V>(&mut map, "width", location)?;
                Ok(Table::Pwm { width })
            }
            "pipe" => {
                let first_raw = map.remove("first").ok_or_else(|| {
                    deserr::take_cf_content(E::error::<V>(
                        None,
                        ErrorKind::MissingField { field: "first" },
                        location,
                    ))
                })?;
                let second_raw = map.remove("second").ok_or_else(|| {
                    deserr::take_cf_content(E::error::<V>(
                        None,
                        ErrorKind::MissingField { field: "second" },
                        location,
                    ))
                })?;
                let first =
                    Table::deserialize_from_value(first_raw.into_value(), location)?;
                let second =
                    Table::deserialize_from_value(second_raw.into_value(), location)?;
                Ok(Table::Pipe { first: Box::new(first), second: Box::new(second) })
            }
            other => Err(deserr::take_cf_content(E::error::<V>(
                None,
                ErrorKind::Unexpected {
                    msg: format!("unknown table type: {}", other),
                },
                location,
            ))),
        }
    }
}

impl JsonSchema for Table {
    fn schema_name() -> Cow<'static, str> {
        Cow::Borrowed("Table")
    }

    fn json_schema(r#gen: &mut schemars::SchemaGenerator) -> schemars::Schema {
        // Schema matches the serialized form: internally-tagged on "type", camelCase.
        #[derive(JsonSchema)]
        #[serde(tag = "type", rename_all = "camelCase")]
        #[allow(dead_code)]
        enum TableSchema {
            Identity,
            Mirror { amount: PolySignal },
            Bend { amount: PolySignal },
            Sync { ratio: PolySignal },
            Fold { amount: PolySignal },
            Pwm { width: PolySignal },
            Pipe { first: Box<Table>, second: Box<Table> },
        }
        TableSchema::json_schema(r#gen)
    }
}

/// A single-channel signal value.
///
/// This represents either a constant voltage or a cable connection to a specific
/// channel of another module's output.
#[derive(Clone, Debug)]
pub enum Signal {
    /// Static voltage value (mono)
    Volts(f32),
    /// Cable connection to another module's output at a specific channel
    Cable {
        module: String,
        module_ptr: std::sync::Weak<Box<dyn Sampleable>>,
        port: String,
        /// Which channel of the output to read (0-indexed)
        channel: usize,
        /// Back-pointer to the consuming wrapper's `index: Cell<usize>`.
        /// Null until `inject_index_ptr` is called during `connect()`.
        /// Raw pointer is safe because the wrapper owns the `Cell` and outlives
        /// all `Signal`s that reference it.
        index_ptr: *const std::cell::Cell<usize>,
    },
}

// SAFETY: `index_ptr` is null during construction and transport; it is only
// written/read on the audio thread after `inject_index_ptr` is called during
// `connect()`. The wrapper that owns the pointed-to `Cell` also upholds
// `unsafe impl Send + Sync`.
unsafe impl Send for Signal {}
unsafe impl Sync for Signal {}

// Custom serde deserialization to allow a bare number as shorthand for volts.
//
// Examples accepted:
// - 0.5                      -> Signal::Volts(0.5)
// - "440hz"                  -> Signal::Volts(computed voltage)
// - { type: 'cable', module, port, channel } -> Signal::Cable
//
// Note: Arrays are no longer accepted for Signal - use PolySignal for polyphonic inputs.
impl<'de> Deserialize<'de> for Signal {
    fn deserialize<D>(deserializer: D) -> std::result::Result<Self, D::Error>
    where
        D: serde::Deserializer<'de>,
    {
        #[derive(Deserialize)]
        #[serde(untagged)]
        enum SignalDe {
            Number(f64),
            String(String),
            Tagged(SignalTagged),
        }

        #[derive(Deserialize)]
        #[serde(
            tag = "type",
            rename_all = "camelCase",
            rename_all_fields = "camelCase"
        )]
        enum SignalTagged {
            Cable {
                module: String,
                port: String,
                #[serde(default)]
                channel: usize,
            },
        }

        match SignalDe::deserialize(deserializer)? {
            SignalDe::Number(value) => Ok(Signal::Volts(value as f32)),
            SignalDe::String(s) => parse_signal_string(&s)
                .map(Signal::Volts)
                .map_err(serde::de::Error::custom),
            SignalDe::Tagged(tagged) => Ok(match tagged {
                SignalTagged::Cable {
                    module,
                    port,
                    channel,
                } => Signal::Cable {
                    module,
                    module_ptr: sync::Weak::new(),
                    port,
                    channel,
                    index_ptr: std::ptr::null(),
                },
            }),
        }
    }
}

impl serde::Serialize for Signal {
    fn serialize<S>(&self, serializer: S) -> std::result::Result<S::Ok, S::Error>
    where
        S: serde::Serializer,
    {
        use serde::ser::SerializeMap;
        match self {
            Signal::Volts(v) => serializer.serialize_f32(*v),
            Signal::Cable {
                module,
                port,
                channel,
                ..
            } => {
                let mut map = serializer.serialize_map(Some(4))?;
                map.serialize_entry("type", "cable")?;
                map.serialize_entry("module", module)?;
                map.serialize_entry("port", port)?;
                map.serialize_entry("channel", channel)?;
                map.end()
            }
        }
    }
}

// deserr implementation for Signal - mirrors the serde Deserialize impl above.
//
// Accepts:
//   - number (integer or float) -> Signal::Volts
//   - string (e.g. "440hz", "C4") -> Signal::Volts (parsed via parse_signal_string)
//   - object { type: "cable", module, port, channel? } -> Signal::Cable
impl<E: DeserializeError> deserr::Deserr<E> for Signal {
    fn deserialize_from_value<V: IntoValue>(
        value: deserr::Value<V>,
        location: ValuePointerRef<'_>,
    ) -> std::result::Result<Self, E> {
        match value {
            deserr::Value::Integer(n) => Ok(Signal::Volts(n as f32)),
            deserr::Value::NegativeInteger(n) => Ok(Signal::Volts(n as f32)),
            deserr::Value::Float(n) => Ok(Signal::Volts(n as f32)),
            deserr::Value::String(s) => parse_signal_string(&s).map(Signal::Volts).map_err(|e| {
                deserr::take_cf_content(E::error::<V>(
                    None,
                    ErrorKind::Unexpected { msg: e },
                    location,
                ))
            }),
            deserr::Value::Map(mut map) => {
                let type_val = map
                    .remove("type")
                    .and_then(|v| match v.into_value() {
                        deserr::Value::String(s) => Some(s),
                        _ => None,
                    });

                let module = map
                    .remove("module")
                    .and_then(|v| match v.into_value() {
                        deserr::Value::String(s) => Some(s),
                        _ => None,
                    });

                let port = map
                    .remove("port")
                    .and_then(|v| match v.into_value() {
                        deserr::Value::String(s) => Some(s),
                        _ => None,
                    });

                let channel = map
                    .remove("channel")
                    .and_then(|v| match v.into_value() {
                        deserr::Value::Integer(n) => Some(n as usize),
                        _ => None,
                    })
                    .unwrap_or(0);

                match type_val.as_deref() {
                    Some("cable") => {
                        let module = module.ok_or_else(|| {
                            deserr::take_cf_content(E::error::<V>(
                                None,
                                ErrorKind::MissingField { field: "module" },
                                location,
                            ))
                        })?;
                        let port = port.ok_or_else(|| {
                            deserr::take_cf_content(E::error::<V>(
                                None,
                                ErrorKind::MissingField { field: "port" },
                                location,
                            ))
                        })?;
                        Ok(Signal::Cable {
                            module,
                            module_ptr: sync::Weak::new(),
                            port,
                            channel,
                            index_ptr: std::ptr::null(),
                        })
                    }
                    Some(other) => Err(deserr::take_cf_content(E::error::<V>(
                        None,
                        ErrorKind::Unexpected {
                            msg: format!("unknown signal type: {}", other),
                        },
                        location,
                    ))),
                    None => Err(deserr::take_cf_content(E::error::<V>(
                        None,
                        ErrorKind::MissingField { field: "type" },
                        location,
                    ))),
                }
            }
            _ => Err(deserr::take_cf_content(E::error::<V>(
                None,
                ErrorKind::Unexpected {
                    msg: "Invalid signal format".to_string(),
                },
                location,
            ))),
        }
    }
}

