impl Signal {
    /// Get the mono voltage value from this signal.
    /// For Volts, returns the stored value.
    /// For Cable, fetches the specific channel from the connected module's output.
    pub fn get_value(&self) -> f32 {
        match self {
            Signal::Volts(v) => *v,
            Signal::Cable {
                module_ptr,
                port,
                channel,
                index_ptr,
                module: _,
            } => match module_ptr.upgrade() {
                Some(module_ptr) => {
                    let index = if index_ptr.is_null() {
                        0
                    } else {
                        let cell: &std::cell::Cell<usize> = unsafe { &**index_ptr };
                        cell.get()
                    };
                    // Channel cycling is handled inside get_value_at.
                    module_ptr.get_value_at(port, *channel, index)
                }
                None => 0.0,
            },
        }
    }
}

impl InjectIndexPtr for Signal {
    fn inject_index_ptr(&mut self, ptr: *const std::cell::Cell<usize>) {
        if let Signal::Cable { index_ptr, .. } = self {
            *index_ptr = ptr;
        }
    }
}

/// Extension trait for normalling pattern on optional signals.
pub trait SignalExt {
    /// Returns the signal's value, or `default` if None.
    fn value_or(&self, default: f32) -> f32;

    /// Returns the signal's value, or calls `f` if None.
    fn value_or_else(&self, f: impl FnOnce() -> f32) -> f32;

    /// Returns the signal's value, or 0.0 if None.
    fn value_or_zero(&self) -> f32;
}

impl SignalExt for Option<Signal> {
    fn value_or(&self, default: f32) -> f32 {
        match self {
            Some(s) => s.get_value(),
            None => default,
        }
    }

    fn value_or_else(&self, f: impl FnOnce() -> f32) -> f32 {
        match self {
            Some(s) => s.get_value(),
            None => f(),
        }
    }

    fn value_or_zero(&self) -> f32 {
        match self {
            Some(s) => s.get_value(),
            None => 0.0,
        }
    }
}

impl Connect for Signal {
    fn connect(&mut self, patch: &Patch) {
        if let Signal::Cable {
            module, module_ptr, ..
        } = self
            && let Some(sampleable) = patch.sampleables.get(module)
        {
            *module_ptr = Arc::downgrade(sampleable);
        }
    }
}

impl PartialEq for Box<dyn Sampleable> {
    fn eq(&self, other: &Self) -> bool {
        self.get_id() == other.get_id()
    }
}

impl PartialEq for Signal {
    fn eq(&self, other: &Self) -> bool {
        match (self, other) {
            (Signal::Volts(v1), Signal::Volts(v2)) => v1 == v2,
            (
                Signal::Cable {
                    module: module_1,
                    module_ptr: module_ptr_1,
                    port: port_1,
                    channel: channel_1,
                    ..
                },
                Signal::Cable {
                    module: module_2,
                    module_ptr: module_ptr_2,
                    port: port_2,
                    channel: channel_2,
                    ..
                },
            ) => {
                module_ptr_1.upgrade() == module_ptr_2.upgrade()
                    && port_1 == port_2
                    && module_1 == module_2
                    && channel_1 == channel_2
            }
            _ => false,
        }
    }
}

