#[cfg(test)]
mod tests {
    use super::*;
    use serde_json::from_str;

    #[test]
    fn test_signal_deserialization_volts() {
        let s: Signal = from_str("0.5").unwrap();
        match s {
            Signal::Volts(v) => assert_eq!(v, 0.5),
            _ => panic!("Expected Volts"),
        }
    }

    #[test]
    fn test_signal_deserialization_hz() {
        // C4 (~261.63Hz) is 0V
        let s: Signal = from_str("\"261.6255653005986hz\"").unwrap();
        match s {
            Signal::Volts(v) => assert!(v.abs() < 1e-5, "C4 should be 0V, got {}", v),
            _ => panic!("Expected Volts"),
        }

        // C5 (~523.25Hz) is 1V (one octave up)
        let s: Signal = from_str("\"523.2511306011972hz\"").unwrap();
        match s {
            Signal::Volts(v) => assert!((v - 1.0).abs() < 1e-5, "C5 should be 1V, got {}", v),
            _ => panic!("Expected Volts"),
        }
    }

    #[test]
    fn test_signal_deserialization_midi() {
        // MIDI 60 (C4) is 0V
        let s: Signal = from_str("\"60m\"").unwrap();
        match s {
            Signal::Volts(v) => assert!(v.abs() < 1e-6, "MIDI 60 should be 0V, got {}", v),
            _ => panic!("Expected Volts"),
        }

        // MIDI 72 (C5) is 1V
        let s: Signal = from_str("\"72m\"").unwrap();
        match s {
            Signal::Volts(v) => assert!((v - 1.0).abs() < 1e-6, "MIDI 72 should be 1V, got {}", v),
            _ => panic!("Expected Volts"),
        }
    }

    #[test]
    fn test_signal_deserialization_note() {
        // C4 (Middle C) is 0V
        let s: Signal = from_str("\"C4\"").unwrap();
        match s {
            Signal::Volts(v) => assert!(v.abs() < 1e-6, "C4 should be 0V, got {}", v),
            _ => panic!("Expected Volts"),
        }

        // C3 is -1V
        let s: Signal = from_str("\"C3\"").unwrap();
        match s {
            Signal::Volts(v) => assert!((v + 1.0).abs() < 1e-6, "C3 should be -1V, got {}", v),
            _ => panic!("Expected Volts"),
        }

        // C5 is 1V
        let s: Signal = from_str("\"C5\"").unwrap();
        match s {
            Signal::Volts(v) => assert!((v - 1.0).abs() < 1e-6, "C5 should be 1V, got {}", v),
            _ => panic!("Expected Volts"),
        }

        // A4 (440Hz) -> MIDI 69 -> (69-60)/12 = 0.75V
        let s: Signal = from_str("\"A4\"").unwrap();
        match s {
            Signal::Volts(v) => assert!((v - 0.75).abs() < 1e-6, "A4 should be 0.75V, got {}", v),
            _ => panic!("Expected Volts"),
        }

        // Sharps/Flats
        // C#4 -> MIDI 61 -> 1/12 V
        let s: Signal = from_str("\"C#4\"").unwrap();
        match s {
            Signal::Volts(v) => assert!(
                (v - (1.0 / 12.0)).abs() < 1e-6,
                "C#4 should be 1/12V, got {}",
                v
            ),
            _ => panic!("Expected Volts"),
        }
    }

    #[test]
    fn test_signal_deserialization_scale() {
        // 0s(C4:Major) -> treat as root -> C4 -> 0V
        let s: Signal = from_str("\"0s(C4:Major)\"").unwrap();
        match s {
            Signal::Volts(v) => assert!(v.abs() < 1e-6, "0s(C4:Major) should be 0V, got {}", v),
            _ => panic!("Expected Volts"),
        }

        // 1s(C4:Major) -> 2nd interval -> D4 -> 2 semitones -> 2/12 V
        let s: Signal = from_str("\"1s(C4:Major)\"").unwrap();
        match s {
            Signal::Volts(v) => assert!(
                (v - (2.0 / 12.0)).abs() < 1e-6,
                "1s(C4:Major) should be 2/12V, got {}",
                v
            ),
            _ => panic!("Expected Volts"),
        }

        // 2s(C4:Major) -> 3rd interval -> E4 -> 4 semitones -> 4/12 V
        let s: Signal = from_str("\"2s(C4:Major)\"").unwrap();
        match s {
            Signal::Volts(v) => assert!(
                (v - (4.0 / 12.0)).abs() < 1e-6,
                "2s(C4:Major) should be 4/12V, got {}",
                v
            ),
            _ => panic!("Expected Volts"),
        }

        // 7s(C4:Major) -> 8th interval (octave) -> C5 -> 12 semitones -> 1V
        let s: Signal = from_str("\"7s(C4:Major)\"").unwrap();
        match s {
            Signal::Volts(v) => assert!(
                (v - 1.0).abs() < 1e-6,
                "7s(C4:Major) should be 1V, got {}",
                v
            ),
            _ => panic!("Expected Volts"),
        }

        // Cents
        // 1.5s(C4:Major) -> 2nd interval + 50 cents -> 2.5 semitones -> 2.5/12 V
        let s: Signal = from_str("\"1.5s(c4:maj)\"").unwrap();
        match s {
            Signal::Volts(v) => assert!(
                (v - (2.5 / 12.0)).abs() < 1e-6,
                "1.5s(C4:Major) should be 2.5/12V, got {}",
                v
            ),
            _ => panic!("Expected Volts"),
        }

        // Negative degrees wrap to lower octave
        // -1s(C4:Major) -> B3 -> one semitone below C4 -> -1/12 V
        let s: Signal = from_str("\"-1s(C4:Major)\"").unwrap();
        match s {
            Signal::Volts(v) => assert!(
                (v - (-1.0 / 12.0)).abs() < 1e-6,
                "-1s(C4:Major) should be -1/12V, got {}",
                v
            ),
            _ => panic!("Expected Volts"),
        }
    }

    #[test]
    fn test_signal_deserialization_errors() {
        assert!(from_str::<Signal>("\"invalid\"").is_err());
        assert!(from_str::<Signal>("\"-10hz\"").is_err());
    }

    /// Fill a buffer with sequential values where the value at age `a` (frames ago
    /// from write_idx) is `(a + 1) as f32`. Only fills frames that would actually
    /// have been written (ages 0..min(frame_count, write_idx+1)), mirroring how
    /// the real audio thread advances the write head from 0.
    fn fill_buffer_sequential(buf: &BufferData, write_idx: usize) {
        let frame_count = buf.frame_count();
        buf.set_write_index(write_idx);
        let frames_written = frame_count.min(write_idx.saturating_add(1));
        for age in 0..frames_written {
            let pos = write_idx.wrapping_sub(age) % frame_count;
            for ch in 0..buf.channel_count() {
                buf.write(ch, pos, (age + 1) as f32 + ch as f32 * 1000.0);
            }
        }
    }

    /// Verify that a delay read at `age` frames ago from `write_idx` returns the
    /// expected value. Mirrors how $delayRead computes positions.
    fn read_at_age(buf: &BufferData, channel: usize, write_idx: usize, age: usize) -> f32 {
        let pos = write_idx.wrapping_sub(age) % buf.frame_count();
        buf.read(channel, pos)
    }

    #[test]
    fn test_copy_overlap_shrink_mid_buffer_write_head() {
        // Old: 8 frames, write_idx=42 (42%8=2, so most recent write at frame 2)
        // New: 5 frames
        // Should preserve the 5 most recent frames (ages 0..4)
        let old = BufferData::new_zeroed(1, 8);
        fill_buffer_sequential(&old, 42);

        let new = BufferData::new_zeroed(1, 5);
        new.copy_overlap_from(&old);

        assert_eq!(new.read_write_index(), 42);
        for age in 0..5 {
            let val = read_at_age(&new, 0, 42, age);
            assert_eq!(val, (age + 1) as f32, "age {} should be {}", age, age + 1);
        }
    }

    #[test]
    fn test_copy_overlap_grow() {
        // Old: 5 frames, write_idx=42
        // New: 8 frames
        // All 5 old frames should be present; remaining 3 should be zero
        let old = BufferData::new_zeroed(1, 5);
        fill_buffer_sequential(&old, 42);

        let new = BufferData::new_zeroed(1, 8);
        new.copy_overlap_from(&old);

        assert_eq!(new.read_write_index(), 42);
        // Ages 0..4 should have data
        for age in 0..5 {
            let val = read_at_age(&new, 0, 42, age);
            assert_eq!(val, (age + 1) as f32, "age {} should be {}", age, age + 1);
        }
        // Ages 5..7 should be zero (unwritten)
        for age in 5..8 {
            let val = read_at_age(&new, 0, 42, age);
            assert_eq!(val, 0.0, "age {} should be zero", age);
        }
    }

    #[test]
    fn test_copy_overlap_same_size() {
        let old = BufferData::new_zeroed(1, 8);
        fill_buffer_sequential(&old, 42);

        let new = BufferData::new_zeroed(1, 8);
        new.copy_overlap_from(&old);

        assert_eq!(new.read_write_index(), 42);
        for age in 0..8 {
            let val = read_at_age(&new, 0, 42, age);
            assert_eq!(val, (age + 1) as f32, "age {} should be {}", age, age + 1);
        }
    }

    #[test]
    fn test_copy_overlap_write_head_at_zero() {
        // write_idx=0 means only 1 frame has been written (at position 0).
        // Only that single frame should be copied; the rest stays zero.
        let old = BufferData::new_zeroed(1, 8);
        fill_buffer_sequential(&old, 0);

        let new = BufferData::new_zeroed(1, 5);
        new.copy_overlap_from(&old);

        assert_eq!(new.read_write_index(), 0);
        // Age 0 (the one frame written) should be preserved
        let val = read_at_age(&new, 0, 0, 0);
        assert_eq!(val, 1.0, "age 0 should be 1.0");
        // All other positions should be zero
        for frame in 1..5 {
            assert_eq!(new.read(0, frame), 0.0, "frame {} should be zero", frame);
        }
    }

    #[test]
    fn test_copy_overlap_large_monotonic_counter() {
        // write_idx near usize::MAX to test wrapping_sub correctness.
        // This relies on wrapping arithmetic matching modular arithmetic for
        // power-of-two-friendly buffer sizes. The test is valid on both 32-bit
        // and 64-bit targets, but the specific overflow boundary differs.
        let write_idx = usize::MAX - 3;
        let old = BufferData::new_zeroed(1, 8);
        fill_buffer_sequential(&old, write_idx);

        let new = BufferData::new_zeroed(1, 5);
        new.copy_overlap_from(&old);

        assert_eq!(new.read_write_index(), write_idx);
        for age in 0..5 {
            let val = read_at_age(&new, 0, write_idx, age);
            assert_eq!(val, (age + 1) as f32, "age {} should be {}", age, age + 1);
        }
    }

    #[test]
    fn test_copy_overlap_multi_channel() {
        let old = BufferData::new_zeroed(3, 8);
        fill_buffer_sequential(&old, 42);

        let new = BufferData::new_zeroed(3, 5);
        new.copy_overlap_from(&old);

        assert_eq!(new.read_write_index(), 42);
        for ch in 0..3 {
            for age in 0..5 {
                let val = read_at_age(&new, ch, 42, age);
                let expected = (age + 1) as f32 + ch as f32 * 1000.0;
                assert_eq!(val, expected, "ch {} age {} should be {}", ch, age, expected);
            }
        }
    }

    #[test]
    fn test_copy_overlap_zero_size_old() {
        let old = BufferData::new_zeroed(1, 0);
        let new = BufferData::new_zeroed(1, 5);
        new.copy_overlap_from(&old);
        // Should not panic, write index should be 0
        assert_eq!(new.read_write_index(), 0);
    }

    #[test]
    fn test_copy_overlap_zero_size_new() {
        let old = BufferData::new_zeroed(1, 8);
        fill_buffer_sequential(&old, 42);
        let new = BufferData::new_zeroed(1, 0);
        new.copy_overlap_from(&old);
        // Should not panic, write index preserved
        assert_eq!(new.read_write_index(), 42);
    }

    /// Exhaustive same-size test: for every write_idx position within the buffer,
    /// verify that copy_overlap_from produces a byte-identical copy. This simulates
    /// what happens during a forced patch update when buffer length doesn't change.
    #[test]
    fn test_copy_overlap_same_size_every_write_position() {
        let buf_size = 64;
        // Test write_idx values that produce every possible (write_idx % buf_size)
        for offset in 0..buf_size {
            // Use a large base to simulate a realistic monotonic counter
            let write_idx = 100_000 + offset;
            let old = BufferData::new_zeroed(2, buf_size);
            fill_buffer_sequential(&old, write_idx);

            let new = BufferData::new_zeroed(2, buf_size);
            new.copy_overlap_from(&old);

            assert_eq!(new.read_write_index(), write_idx, "offset={}", offset);

            // Every frame at every age should match the original
            for ch in 0..2 {
                for age in 0..buf_size {
                    let old_val = read_at_age(&old, ch, write_idx, age);
                    let new_val = read_at_age(&new, ch, write_idx, age);
                    assert_eq!(
                        old_val, new_val,
                        "Mismatch: ch={} age={} write_idx={} (offset={})",
                        ch, age, write_idx, offset
                    );
                }
            }
        }
    }

    /// Exhaustive shrink test: for every write_idx position, verify that the
    /// most recent frames are preserved when shrinking the buffer.
    #[test]
    fn test_copy_overlap_shrink_every_write_position() {
        let old_size = 64;
        let new_size = 40;
        for offset in 0..old_size {
            let write_idx = 100_000 + offset;
            let old = BufferData::new_zeroed(1, old_size);
            fill_buffer_sequential(&old, write_idx);

            let new = BufferData::new_zeroed(1, new_size);
            new.copy_overlap_from(&old);

            assert_eq!(new.read_write_index(), write_idx, "offset={}", offset);

            // The most recent new_size frames should match
            for age in 0..new_size {
                let old_val = read_at_age(&old, 0, write_idx, age);
                let new_val = read_at_age(&new, 0, write_idx, age);
                assert_eq!(
                    old_val, new_val,
                    "Mismatch: age={} write_idx={} (offset={})",
                    age, write_idx, offset
                );
            }
        }
    }

    /// Exhaustive grow test: for every write_idx position, verify that all
    /// old frames are preserved and extra positions are zero.
    #[test]
    fn test_copy_overlap_grow_every_write_position() {
        let old_size = 40;
        let new_size = 64;
        for offset in 0..old_size {
            let write_idx = 100_000 + offset;
            let old = BufferData::new_zeroed(1, old_size);
            fill_buffer_sequential(&old, write_idx);

            let new = BufferData::new_zeroed(1, new_size);
            new.copy_overlap_from(&old);

            assert_eq!(new.read_write_index(), write_idx, "offset={}", offset);

            // The most recent old_size frames should match
            for age in 0..old_size {
                let old_val = read_at_age(&old, 0, write_idx, age);
                let new_val = read_at_age(&new, 0, write_idx, age);
                assert_eq!(
                    old_val, new_val,
                    "Mismatch: age={} write_idx={} (offset={})",
                    age, write_idx, offset
                );
            }

            // Older positions (ages old_size..new_size) should be zero
            for age in old_size..new_size {
                let val = read_at_age(&new, 0, write_idx, age);
                assert_eq!(
                    val, 0.0,
                    "Expected zero at age={} write_idx={} (offset={})",
                    age, write_idx, offset
                );
            }
        }
    }
}

#[cfg(test)]
mod sample_buffer_tests {
    use super::*;

    #[test]
    fn sample_buffer_new_zeroed() {
        let buf = SampleBuffer::new_zeroed(2, 100, 48000.0);
        assert_eq!(buf.channel_count(), 2);
        assert_eq!(buf.frame_count(), 100);
        assert_eq!(buf.read(0, 0), 0.0);
        assert_eq!(buf.read(1, 99), 0.0);
    }

    #[test]
    fn sample_buffer_from_samples() {
        let samples = vec![vec![1.0, 2.0, 3.0], vec![4.0, 5.0, 6.0]];
        let buf = SampleBuffer::from_samples(samples, 48000.0);
        assert_eq!(buf.channel_count(), 2);
        assert_eq!(buf.frame_count(), 3);
        assert_eq!(buf.read(0, 1), 2.0);
        assert_eq!(buf.read(1, 2), 6.0);
    }

    #[test]
    fn sample_buffer_write_and_read() {
        let mut buf = SampleBuffer::new_zeroed(1, 10, 48000.0);
        buf.write(0, 5, 42.0);
        assert_eq!(buf.read(0, 5), 42.0);
    }

    #[test]
    fn sample_buffer_read_out_of_bounds_returns_zero() {
        let buf = SampleBuffer::new_zeroed(1, 5, 48000.0);
        assert_eq!(buf.read(0, 10), 0.0); // frame out of range
        assert_eq!(buf.read(5, 0), 0.0); // channel out of range
    }

    #[test]
    fn sample_buffer_fill() {
        let mut buf = SampleBuffer::new_zeroed(2, 3, 48000.0);
        buf.fill(7.0);
        for ch in 0..2 {
            for frame in 0..3 {
                assert_eq!(buf.read(ch, frame), 7.0);
            }
        }
    }

    #[test]
    fn sample_buffer_snapshot() {
        let samples = vec![vec![1.0, 2.0], vec![3.0, 4.0]];
        let buf = SampleBuffer::from_samples(samples.clone(), 48000.0);
        assert_eq!(buf.snapshot(), samples);
    }

    #[test]
    fn sample_buffer_with_data() {
        let buf = SampleBuffer::from_samples(vec![vec![10.0, 20.0]], 48000.0);
        let sum: f32 = buf.with_data(|data| data[0].iter().sum());
        assert_eq!(sum, 30.0);
    }
}

#[cfg(test)]
mod wav_tests {
    use super::*;
    use std::sync::Arc;

    #[test]
    fn wav_data_from_samples() {
        let samples = vec![vec![1.0, 2.0, 3.0], vec![4.0, 5.0, 6.0]];
        let wav = WavData::new(SampleBuffer::from_samples(samples, 44100.0), None);
        assert_eq!(wav.channel_count(), 2);
        assert_eq!(wav.frame_count(), 3);
        assert_eq!(wav.sample_rate(), 44100.0);
        assert_eq!(wav.read(0, 1), 2.0);
        assert_eq!(wav.read(1, 2), 6.0);
    }

    #[test]
    fn wav_data_is_send_sync() {
        fn assert_send_sync<T: Send + Sync>() {}
        assert_send_sync::<WavData>();
        assert_send_sync::<Arc<WavData>>();
    }

    #[test]
    fn wav_param_unconnected_returns_zeros() {
        let wav = Wav::new("test/kick".to_string(), 2);
        assert_eq!(wav.channel_count(), 2);
        assert_eq!(wav.frame_count(), 0);
        assert!(!wav.is_loaded());
        assert_eq!(wav.read(0, 0), 0.0);
    }

    #[test]
    fn wav_param_connect_resolves_data() {
        let samples = vec![vec![1.0, 2.0], vec![3.0, 4.0]];
        let wav_data = Arc::new(WavData::new(
            SampleBuffer::from_samples(samples, 48000.0),
            None,
        ));

        let mut patch = Patch::new();
        patch.wav_data.insert("test/kick".to_string(), wav_data);

        let mut wav = Wav::new("test/kick".to_string(), 2);
        wav.connect(&patch);

        assert!(wav.is_loaded());
        assert_eq!(wav.frame_count(), 2);
        assert_eq!(wav.read(0, 0), 1.0);
        assert_eq!(wav.read(1, 1), 4.0);
    }

    #[test]
    fn wav_param_connect_missing_path_stays_unloaded() {
        let patch = Patch::new();
        let mut wav = Wav::new("nonexistent".to_string(), 1);
        wav.connect(&patch);
        assert!(!wav.is_loaded());
    }

    #[test]
    fn wav_deserializes_without_mtime_via_serde() {
        let w: Wav =
            serde_json::from_str(r#"{"type":"wav_ref","path":"kick","channels":2}"#).unwrap();
        assert_eq!(w.path(), "kick");
        assert_eq!(w.channel_count(), 2);
        assert_eq!(w.mtime(), None);
    }

    #[test]
    fn wav_deserializes_with_mtime_via_serde() {
        let w: Wav = serde_json::from_str(
            r#"{"type":"wav_ref","path":"kick","channels":2,"mtime":123.0}"#,
        )
        .unwrap();
        assert_eq!(w.mtime(), Some(123.0));
        // round-trip: serialize back out and confirm mtime preserved
        let out = serde_json::to_string(&w).unwrap();
        assert!(out.contains("\"mtime\":123"), "mtime not in output: {out}");
    }

    #[test]
    fn wav_serializes_without_mtime_when_absent() {
        let w: Wav =
            serde_json::from_str(r#"{"type":"wav_ref","path":"kick","channels":2}"#).unwrap();
        let out = serde_json::to_string(&w).unwrap();
        assert!(
            !out.contains("mtime"),
            "mtime should be omitted when None, got: {out}"
        );
    }

    #[test]
    fn wav_deserializes_without_mtime_via_deserr() {
        let v: serde_json::Value =
            serde_json::from_str(r#"{"type":"wav_ref","path":"kick","channels":2}"#).unwrap();
        let w: Wav = deserr::deserialize::<Wav, _, deserr::errors::JsonError>(v).unwrap();
        assert_eq!(w.path(), "kick");
        assert_eq!(w.channel_count(), 2);
        assert_eq!(w.mtime(), None);
    }
}

#[cfg(test)]
mod table_tests {
    use super::*;
    use crate::poly::PolySignal;

    fn constant(v: f32) -> PolySignal {
        PolySignal::mono(Signal::Volts(v))
    }

    // ---------- evaluate() ----------

    #[test]
    fn identity_evaluates_as_passthrough() {
        let t = Table::Identity;
        for i in 0..=10 {
            let x = i as f32 / 10.0;
            assert!((t.evaluate(x, 0) - x).abs() < 1e-6);
        }
    }

    #[test]
    fn mirror_evaluates_with_constant_signal() {
        let t = Table::Mirror { amount: constant(0.0) };
        // amount=0 => identity.
        for i in 0..=10 {
            let x = i as f32 / 10.0;
            assert!((t.evaluate(x, 0) - x).abs() < 1e-6);
        }
        // amount=1 at midpoint => 1.0.
        let t = Table::Mirror { amount: constant(1.0) };
        assert!((t.evaluate(0.5, 0) - 1.0).abs() < 1e-6);
    }

    #[test]
    fn bend_evaluates_with_constant_signal() {
        let t = Table::Bend { amount: constant(0.0) };
        for i in 0..=10 {
            let x = i as f32 / 10.0;
            assert!((t.evaluate(x, 0) - x).abs() < 1e-6);
        }
        // Endpoints preserved even under bend.
        let t = Table::Bend { amount: constant(0.7) };
        assert!(t.evaluate(0.0, 0).abs() < 1e-6);
        assert!((t.evaluate(1.0, 0) - 1.0).abs() < 1e-6);
    }

    #[test]
    fn sync_evaluates_with_constant_signal() {
        // ratio=0 => 1x (identity on [0, 1)).
        let t = Table::Sync { ratio: constant(0.0) };
        for i in 0..100 {
            let x = i as f32 / 100.0;
            assert!((t.evaluate(x, 0) - x).abs() < 1e-6);
        }
    }

    #[test]
    fn fold_evaluates_with_constant_signal() {
        // amount=0 => identity.
        let t = Table::Fold { amount: constant(0.0) };
        for i in 0..=10 {
            let x = i as f32 / 10.0;
            assert!((t.evaluate(x, 0) - x).abs() < 1e-6);
        }
    }

    #[test]
    fn pwm_evaluates_with_constant_signal() {
        let t = Table::Pwm { width: constant(0.5) };
        assert!(t.evaluate(0.0, 0).abs() < 1e-6);
        assert!((t.evaluate(1.0, 0) - 1.0).abs() < 1e-6);
    }

    #[test]
    fn evaluate_output_in_range_across_sweep() {
        let cases: Vec<Table> = vec![
            Table::Identity,
            Table::Mirror { amount: constant(0.5) },
            Table::Bend { amount: constant(0.5) },
            Table::Sync { ratio: constant(0.5) },
            Table::Fold { amount: constant(0.5) },
            Table::Pwm { width: constant(0.3) },
        ];
        for t in &cases {
            for i in 0..=100 {
                let x = i as f32 / 100.0;
                let y = t.evaluate(x, 0);
                assert!(
                    (0.0..=1.0).contains(&y),
                    "table variant output {} out of range for x={}",
                    y,
                    x
                );
            }
        }
    }

    // ---------- connect() ----------

    #[test]
    fn connect_identity_is_noop() {
        let patch = Patch::new();
        let mut t = Table::Identity;
        t.connect(&patch);
        assert!(matches!(t, Table::Identity));
    }

    #[test]
    fn connect_resolves_polysignal_for_every_variant() {
        // With PolySignal::mono(Signal::Volts(x)), `connect()` is a no-op on Volts,
        // so we mostly assert that it runs without panic and evaluates sensibly.
        let patch = Patch::new();

        let mut mirror = Table::Mirror { amount: constant(0.25) };
        mirror.connect(&patch);
        // At x=0.5 the reflection is 1.0; interpolated at amount=0.25: 0.5 + 0.5*0.25 = 0.625.
        assert!((mirror.evaluate(0.5, 0) - 0.625).abs() < 1e-4);

        let mut bend = Table::Bend { amount: constant(0.0) };
        bend.connect(&patch);
        assert!((bend.evaluate(0.5, 0) - 0.5).abs() < 1e-6);

        let mut sync = Table::Sync { ratio: constant(0.0) };
        sync.connect(&patch);
        assert!((sync.evaluate(0.25, 0) - 0.25).abs() < 1e-6);

        let mut fold = Table::Fold { amount: constant(0.0) };
        fold.connect(&patch);
        assert!((fold.evaluate(0.5, 0) - 0.5).abs() < 1e-6);

        let mut pwm = Table::Pwm { width: constant(0.5) };
        pwm.connect(&patch);
        assert!((pwm.evaluate(0.5, 0) - 0.5).abs() < 1e-6);
    }

    // ---------- (de)serialization round trip ----------

    #[test]
    fn table_deserializes_identity() {
        let t: Table = serde_json::from_str(r#"{"type":"identity"}"#).unwrap();
        assert!(matches!(t, Table::Identity));
    }

    #[test]
    fn table_deserializes_mirror_with_scalar_signal() {
        let t: Table =
            serde_json::from_str(r#"{"type":"mirror","amount":0.5}"#).unwrap();
        match t {
            Table::Mirror { amount } => {
                assert!((amount.get_value(0) - 0.5).abs() < 1e-6);
            }
            _ => panic!("expected Mirror"),
        }
    }

    #[test]
    fn table_deserializes_pwm_with_scalar_signal() {
        let t: Table = serde_json::from_str(r#"{"type":"pwm","width":0.25}"#).unwrap();
        match t {
            Table::Pwm { width } => {
                assert!((width.get_value(0) - 0.25).abs() < 1e-6);
            }
            _ => panic!("expected Pwm"),
        }
    }

    #[test]
    fn table_roundtrips_identity() {
        let t = Table::Identity;
        let json = serde_json::to_string(&t).unwrap();
        assert_eq!(json, r#"{"type":"identity"}"#);
    }

    #[test]
    fn table_roundtrips_sync() {
        let t = Table::Sync { ratio: constant(0.75) };
        let json = serde_json::to_string(&t).unwrap();
        let back: Table = serde_json::from_str(&json).unwrap();
        match back {
            Table::Sync { ratio } => {
                assert!((ratio.get_value(0) - 0.75).abs() < 1e-6);
            }
            _ => panic!("expected Sync"),
        }
    }

    // ---------- deserr parity ----------

    #[test]
    fn table_deserr_parses_mirror() {
        use deserr::deserialize;

        let value: serde_json::Value =
            serde_json::from_str(r#"{"type":"mirror","amount":0.5}"#).unwrap();
        let t: Table = deserialize::<Table, _, deserr::errors::JsonError>(value).unwrap();
        match t {
            Table::Mirror { amount } => {
                assert!((amount.get_value(0) - 0.5).abs() < 1e-6);
            }
            _ => panic!("expected Mirror"),
        }
    }

    #[test]
    fn table_deserr_parses_identity() {
        use deserr::deserialize;
        let value: serde_json::Value = serde_json::from_str(r#"{"type":"identity"}"#).unwrap();
        let t: Table = deserialize::<Table, _, deserr::errors::JsonError>(value).unwrap();
        assert!(matches!(t, Table::Identity));
    }

    #[test]
    fn table_deserr_rejects_unknown_type() {
        use deserr::deserialize;
        let value: serde_json::Value = serde_json::from_str(r#"{"type":"bogus"}"#).unwrap();
        let res: StdResult<Table, deserr::errors::JsonError> = deserialize(value);
        assert!(res.is_err());
    }

    // ---------- Pipe composition ----------

    #[test]
    fn pipe_chains_evaluate_first_then_second() {
        // mirror(0.5) at x=0.5 → reflected to 1.0 (full mirror).
        // Then bend(0.0) at 1.0 → 1.0 (identity at amount=0).
        let t = Table::Pipe {
            first: Box::new(Table::Mirror { amount: constant(1.0) }),
            second: Box::new(Table::Bend { amount: constant(0.0) }),
        };
        // At x=0.5, mirror with amount=1 maps 0.5→1.0; bend with 0 maps 1.0→1.0.
        let out = t.evaluate(0.5, 0);
        assert!((out - 1.0).abs() < 1e-4, "expected ~1.0 got {out}");
    }

    #[test]
    fn pipe_channels_is_max_of_both() {
        let t = Table::Pipe {
            first: Box::new(Table::Mirror { amount: constant(0.5) }),
            second: Box::new(Table::Identity),
        };
        assert_eq!(t.channels(), 1); // Mirror has 1, Identity has 0
    }

    #[test]
    fn pipe_serializes_and_deserializes_via_serde() {
        let t = Table::Pipe {
            first: Box::new(Table::Mirror { amount: constant(0.5) }),
            second: Box::new(Table::Bend { amount: constant(0.3) }),
        };
        let json = serde_json::to_string(&t).unwrap();
        assert!(json.contains("\"type\":\"pipe\""), "missing pipe tag: {json}");
        assert!(json.contains("\"type\":\"mirror\""), "missing first: {json}");
        assert!(json.contains("\"type\":\"bend\""), "missing second: {json}");
        let back: Table = serde_json::from_str(&json).unwrap();
        match back {
            Table::Pipe { first, second } => {
                assert!(matches!(*first, Table::Mirror { .. }));
                assert!(matches!(*second, Table::Bend { .. }));
            }
            _ => panic!("expected Pipe"),
        }
    }

    #[test]
    fn pipe_parses_via_deserr() {
        use deserr::deserialize;
        let value: serde_json::Value = serde_json::from_str(
            r#"{"type":"pipe","first":{"type":"mirror","amount":0.5},"second":{"type":"fold","amount":0.2}}"#,
        ).unwrap();
        let t: Table = deserialize::<Table, _, deserr::errors::JsonError>(value).unwrap();
        match t {
            Table::Pipe { first, second } => {
                assert!(matches!(*first, Table::Mirror { .. }));
                assert!(matches!(*second, Table::Fold { .. }));
            }
            _ => panic!("expected Pipe"),
        }
    }
}
